module RefModule (
    input wire clk,
    input wire enable,
    input wire d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (enable) begin
        q <= d;
    end
    // When clock is low or enable is low, the output holds its previous value
end

endmodule
